import base64
from openai import OpenAI
from pathlib import Path

client = OpenAI()

def chart_qa(chart_path: str, question: str, model: str = "gpt-4o") -> str:
    """Answer a question about a chart image using GPT-4o."""
    b64 = base64.b64encode(Path(chart_path).read_bytes()).decode()
    ext = Path(chart_path).suffix.lstrip(".")
    mime = "image/png" if ext == "png" else "image/jpeg"

    response = client.chat.completions.create(
        model=model,
        messages=[
            {
                "role": "system",
                "content": (
                    "You are a chart analysis assistant. "
                    "Read the chart carefully, including axis labels, scale, and legend. "
                    "Answer precisely. If the answer is a number, give only the number "
                    "and its unit. Do not guess."
                ),
            },
            {
                "role": "user",
                "content": [
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": f"data:{mime};base64,{b64}",
                            "detail": "high",   # use high for charts — precision matters
                        },
                    },
                    {"type": "text", "text": question},
                ],
            },
        ],
        max_tokens=256,
    )
    return response.choices[0].message.content

# Examples
print(chart_qa("revenue_bar.png", "What was the revenue in Q3?"))
print(chart_qa("growth_line.png", "In which year did growth peak?"))
print(chart_qa("market_pie.png", "What percentage does 'Others' represent?"))

def relaxed_accuracy(pred: str, gold: str, tol: float = 0.05) -> bool:
    """ChartQA relaxed accuracy: 5% tolerance for numbers, exact match for strings."""
    # Try numeric comparison
    try:
        p = float(pred.replace("%", "").replace(",", "").strip())
        g = float(gold.replace("%", "").replace(",", "").strip())
        return abs(p - g) / max(abs(g), 1e-9) <= tol
    except ValueError:
        pass
    # Fall back to string comparison (case-insensitive, strip whitespace)
    return pred.strip().lower() == gold.strip().lower()

# Evaluate a set of predictions
from datasets import load_dataset

ds = load_dataset("ahmed-masry/ChartQA", split="test")

correct = 0
for example in ds:
    pred = chart_qa(example["image"], example["query"])  # your model
    if relaxed_accuracy(pred, str(example["label"][0])):
        correct += 1

print(f"Relaxed Accuracy: {correct / len(ds):.2%}")
